function ProfileSettings({ t, lang, theme, cardRadius, settingsTab, setSettingsTab }) {
  const tabs = [
    { key:"profile",       label:t.profile_settings_profile },
    { key:"notifications", label:t.profile_settings_notifications },
    { key:"tokens",        label:t.profile_settings_tokens },
  ];
  return (<>
    <ProfileSectionHeader title={t.profile_section_settings} theme={theme}/>
    <div style={{ display:"flex", gap:4, marginBottom:20, borderBottom:`1px solid ${theme.cardBorder}` }}>
      {tabs.map(tb => {
        const active = settingsTab === tb.key;
        return (
          <button key={tb.key} onClick={() => setSettingsTab(tb.key)}
            style={{
              padding:"9px 14px", border:"none", background:"none", cursor:"pointer",
              fontSize:13, fontWeight:active ? 600 : 500, fontFamily:"inherit",
              color: active ? theme.text : theme.textMuted,
              borderBottom:`2px solid ${active ? theme.accent : "transparent"}`,
              marginBottom:-1,
            }}>{tb.label}</button>
        );
      })}
    </div>

    {settingsTab === "profile" && (
      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:16, maxWidth:680 }}>
        <SettingField label={t.profile_settings_name} value={lang==="zh"?PROFILE_USER.nameZh:PROFILE_USER.name} theme={theme}/>
        <SettingField label={t.profile_settings_email} value={PROFILE_USER.email} theme={theme}/>
        <SettingField label={t.profile_settings_dept_label} value={lang==="zh"?"云平台 / 工程部":"Cloud Platform / Engineering"} theme={theme}/>
        <SettingField label={t.profile_joined} value={PROFILE_USER.joined} theme={theme} disabled/>
        <div style={{ gridColumn:"1 / -1" }}>
          <SettingField label={t.profile_settings_bio} value={lang==="zh"?PROFILE_USER.bioZh:PROFILE_USER.bio} theme={theme} multiline/>
        </div>
        <div style={{ gridColumn:"1 / -1", marginTop:8 }}>
          <button style={{ padding:"9px 18px", borderRadius:7, background:theme.accent, color:"#fff", border:"none", cursor:"pointer", fontSize:13, fontWeight:600, fontFamily:"inherit" }}>{t.profile_settings_save}</button>
        </div>
      </div>
    )}

    {settingsTab === "notifications" && (
      <div style={{ display:"flex", flexDirection:"column", gap:2, maxWidth:560 }}>
        {[
          { k:"updates", label:t.profile_notif_updates,  default:true },
          { k:"reviews", label:t.profile_notif_reviews,  default:true },
          { k:"install", label:t.profile_notif_install,  default:false },
          { k:"admin",   label:t.profile_notif_admin,    default:true },
        ].map(n => <NotifRow key={n.k} label={n.label} defaultOn={n.default} theme={theme}/>)}
      </div>
    )}

    {settingsTab === "tokens" && (
      <div>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:14 }}>
          <div style={{ fontSize:13, color:theme.textMuted }}>{t.profile_token_active}</div>
          <button style={{ padding:"7px 14px", borderRadius:7, background:theme.accent, color:"#fff", border:"none", cursor:"pointer", fontSize:12.5, fontWeight:600, fontFamily:"inherit" }}>+ {t.profile_token_create}</button>
        </div>
        <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
          {[
            { name:"ci-bot",      scopes:"read:exts, install", lastUsed:"2h ago" },
            { name:"local-dev",   scopes:"read:exts",          lastUsed:"3d ago" },
          ].map((tok, i) => (
            <div key={i} style={{ padding:"14px 16px", background:theme.cardBg, border:`1px solid ${theme.cardBorder}`, borderRadius:cardRadius, display:"flex", alignItems:"center", gap:14 }}>
              <div style={{ flex:1 }}>
                <div style={{ fontFamily:"'JetBrains Mono', monospace", fontSize:13, fontWeight:600, color:theme.text }}>{tok.name}</div>
                <div style={{ fontSize:12, color:theme.textMuted, marginTop:4, display:"flex", gap:14 }}>
                  <span>{t.profile_token_scopes}: <span style={{ fontFamily:"'JetBrains Mono', monospace" }}>{tok.scopes}</span></span>
                  <span>{t.profile_token_lastused}: {tok.lastUsed}</span>
                </div>
              </div>
              <button style={{ padding:"6px 12px", borderRadius:7, background:"none", border:`1px solid ${theme.cardBorder}`, cursor:"pointer", fontSize:12, fontWeight:600, color:theme.textMuted, fontFamily:"inherit" }}>{t.profile_token_revoke}</button>
            </div>
          ))}
        </div>
      </div>
    )}
  </>);
}

function SettingField({ label, value, theme, disabled, multiline }) {
  return (
    <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
      <label style={{ fontSize:11.5, fontWeight:600, color:theme.textMuted, textTransform:"uppercase", letterSpacing:"0.06em" }}>{label}</label>
      {multiline ? (
        <textarea defaultValue={value} disabled={disabled} rows={3}
          style={{ padding:"10px 12px", borderRadius:7, border:`1px solid ${theme.cardBorder}`, background: disabled ? theme.filterBg : theme.cardBg, color:theme.text, fontSize:13, fontFamily:"inherit", resize:"vertical", outline:"none" }}/>
      ) : (
        <input defaultValue={value} disabled={disabled}
          style={{ padding:"10px 12px", borderRadius:7, border:`1px solid ${theme.cardBorder}`, background: disabled ? theme.filterBg : theme.cardBg, color:theme.text, fontSize:13, fontFamily:"inherit", outline:"none" }}/>
      )}
    </div>
  );
}

function NotifRow({ label, defaultOn, theme }) {
  const [on, setOn] = React.useState(defaultOn);
  return (
    <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", padding:"14px 0", borderBottom:`1px solid ${theme.cardBorder}` }}>
      <div style={{ fontSize:13.5, color:theme.text }}>{label}</div>
      <button onClick={() => setOn(!on)} style={{
        width:36, height:20, borderRadius:10, position:"relative",
        background: on ? theme.accent : theme.cardBorder,
        border:"none", cursor:"pointer", transition:"background 0.18s",
      }}>
        <div style={{ position:"absolute", top:2, left: on ? 18 : 2, width:16, height:16, borderRadius:"50%", background:"#fff", boxShadow:"0 1px 3px rgba(0,0,0,0.15)", transition:"left 0.18s" }}/>
      </button>
    </div>
  );
}

function PublishPage({ lang, t, theme, isDark, cardRadius, density, draft, setDraft, step, setStep, mode, onClose, onSubmitted, onViewListing, onPublishAnother }) {
  // Validate completion of each step
  const stepsValid = [
    !!(draft.name && draft.slug && draft.summary && draft.type && draft.scope),
    draft.sourceMethod === "zip" ? !!draft.zipName : draft.sourceMethod === "git" ? !!draft.gitUrl : true,
    !!(draft.tags.length > 0 && draft.dept && draft.readme),
    true,
  ];
  const canAdvance = stepsValid[step];
  const submit = () => onSubmitted();

  // Success state
  if (step === 4) {
    const willAutoPublish = draft.scope === "personal";
    return (
      <div style={{ maxWidth:520, margin:"80px auto", textAlign:"center", display:"flex", flexDirection:"column", alignItems:"center", gap:18, animation:"fadeIn 0.3s ease" }}>
        <div style={{ width:80, height:80, borderRadius:"50%", background: `${theme.accent}14`, display:"flex", alignItems:"center", justifyContent:"center" }}>
          <Icon name="check" size={40} color={theme.accent}/>
        </div>
        <div className="serif" style={{ fontSize:32, fontWeight:600, letterSpacing:-0.6 }}>{t.pub_success_title}</div>
        <div style={{ fontSize:15, color: theme.textMuted, lineHeight:1.6, maxWidth:400 }}>{willAutoPublish ? t.pub_success_auto : t.pub_success_review}</div>
        <div style={{ display:"flex", gap:10, marginTop:8 }}>
          {willAutoPublish && <button onClick={onViewListing} style={{ padding:"10px 22px", background: theme.accent, color: theme.accentFg, border:"none", borderRadius:8, fontFamily:"inherit", fontSize:13, fontWeight:600, cursor:"pointer" }}>{t.pub_view_listing}</button>}
          <button onClick={onPublishAnother} style={{ padding:"10px 22px", background:"transparent", color: theme.text, border:`1px solid ${theme.cardBorder}`, borderRadius:8, fontFamily:"inherit", fontSize:13, fontWeight:600, cursor:"pointer" }}>{t.pub_publish_another}</button>
          <button onClick={onClose} style={{ padding:"10px 22px", background:"transparent", color: theme.textMuted, border:"none", fontFamily:"inherit", fontSize:13, cursor:"pointer" }}>{t.pub_close}</button>
        </div>
      </div>
    );
  }

  // Header (shared)
  const header = (
    <div style={{ display:"flex", alignItems:"flex-start", justifyContent:"space-between", gap:20, marginBottom: mode === "onepage" ? 28 : 24 }}>
      <div>
        <button onClick={onClose} style={{ background:"none", border:"none", color: theme.textMuted, cursor:"pointer", fontSize:12.5, fontFamily:"inherit", padding:"4px 0", display:"inline-flex", alignItems:"center", gap:5, marginBottom:8 }}>
          <Icon name="chevronLeft" size={12} color={theme.textMuted}/> {t.pub_close}
        </button>
        <h1 className="serif" style={{ fontSize:32, fontWeight:600, letterSpacing:-0.7, margin:0, color: theme.text }}>{t.pub_title}</h1>
        <div style={{ fontSize:13.5, color: theme.textMuted, marginTop:6, maxWidth:560, lineHeight:1.55 }}>{t.pub_subtitle}</div>
      </div>
      <button style={{ background:"transparent", border:`1px solid ${theme.cardBorder}`, padding:"7px 13px", borderRadius:7, fontSize:12, fontWeight:600, color: theme.textMuted, cursor:"pointer", fontFamily:"inherit", flexShrink:0 }}>{t.pub_save_draft}</button>
    </div>
  );

  // Footer (back/next)
  const footer = (
    <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginTop:32, paddingTop:20, borderTop:`1px solid ${theme.cardBorder}` }}>
      <div style={{ fontSize:12, color: theme.textMuted }}>{t.pub_step} {step+1} {t.pub_of} {PUB_STEPS.length}</div>
      <div style={{ display:"flex", gap:10 }}>
        <button onClick={()=>setStep(s => Math.max(0, s-1))} disabled={step === 0} style={{
          padding:"9px 18px", borderRadius:7, border:`1px solid ${theme.cardBorder}`, background:"transparent",
          color: step === 0 ? "#ccc" : theme.text, fontFamily:"inherit", fontSize:13, fontWeight:600,
          cursor: step === 0 ? "not-allowed" : "pointer",
        }}>{t.pub_back}</button>
        {step < PUB_STEPS.length - 1 ? (
          <button onClick={()=>canAdvance && setStep(s => s+1)} disabled={!canAdvance} style={{
            padding:"9px 22px", borderRadius:7, border:"none",
            background: canAdvance ? theme.accent : "#ddd", color: canAdvance ? theme.accentFg : "#999",
            fontFamily:"inherit", fontSize:13, fontWeight:600, cursor: canAdvance ? "pointer" : "not-allowed",
          }}>{t.pub_next} →</button>
        ) : (
          <button onClick={submit} style={{
            padding:"9px 22px", borderRadius:7, border:"none",
            background: theme.accent, color: theme.accentFg,
            fontFamily:"inherit", fontSize:13, fontWeight:600, cursor:"pointer",
          }}>{t.pub_publish}</button>
        )}
      </div>
    </div>
  );

