// @vitest-environment happy-dom
import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
import { render, screen, waitFor, cleanup } from "@testing-library/react";
import userEvent from "@testing-library/user-event";

import { UserButton } from "./user-button";

vi.mock("next-intl", () => ({
  useTranslations: () => (key: string) => key,
}));

const mockPush = vi.fn();
const mockRefresh = vi.fn();
vi.mock("@/lib/i18n/navigation", () => ({
  useRouter: () => ({ push: mockPush, refresh: mockRefresh }),
  Link: ({ href, children, ...props }: { href: string; children: React.ReactNode }) => (
    <a href={href} {...props}>{children}</a>
  ),
}));

const mockUseSession = vi.fn();
const mockSignOut = vi.fn();
vi.mock("@/lib/auth/client", () => ({
  authClient: {
    useSession: () => mockUseSession(),
    signOut: () => mockSignOut(),
  },
}));

afterEach(cleanup);
beforeEach(() => {
  vi.clearAllMocks();
});

describe("UserButton", () => {
  it("renders a Sign in link when there is no session", () => {
    mockUseSession.mockReturnValue({ data: null });

    render(<UserButton />);

    const link = screen.getByRole("link", { name: "signIn" });
    expect(link).toHaveAttribute("href", "/sign-in");
  });

  it("renders an avatar with name initials when authenticated", () => {
    mockUseSession.mockReturnValue({
      data: { user: { name: "Alice Bob", email: "alice@example.com" } },
    });

    render(<UserButton />);

    // Accessible name comes from aria-label; the initials are visual only.
    const button = screen.getByRole("button", { name: "userMenu" });
    expect(button).toBeInTheDocument();
    expect(button).toHaveTextContent("AB");
  });

  it("falls back to the first email letter when name is missing", () => {
    mockUseSession.mockReturnValue({
      data: { user: { name: null, email: "zoe@example.com" } },
    });

    render(<UserButton />);

    expect(
      screen.getByRole("button", { name: "userMenu" }),
    ).toHaveTextContent("Z");
  });

  it("opens the dropdown and shows email + sign out on avatar click", async () => {
    mockUseSession.mockReturnValue({
      data: { user: { name: "Alice Bob", email: "alice@example.com" } },
    });
    const user = userEvent.setup();

    render(<UserButton />);
    await user.click(screen.getByRole("button", { name: "userMenu" }));

    expect(screen.getByText("alice@example.com")).toBeInTheDocument();
    expect(screen.getByRole("button", { name: /signOut/ })).toBeInTheDocument();
  });

  it("calls signOut and navigates home when the sign-out item is clicked", async () => {
    mockUseSession.mockReturnValue({
      data: { user: { name: "Alice Bob", email: "alice@example.com" } },
    });
    mockSignOut.mockResolvedValue(undefined);
    const user = userEvent.setup();

    render(<UserButton />);
    await user.click(screen.getByRole("button", { name: "userMenu" }));
    await user.click(screen.getByRole("button", { name: /signOut/ }));

    await waitFor(() => expect(mockSignOut).toHaveBeenCalledOnce());
    await waitFor(() => expect(mockPush).toHaveBeenCalledWith("/"));
    expect(mockRefresh).toHaveBeenCalled();
  });

  it("exposes haspopup + expanded state on the avatar button", async () => {
    mockUseSession.mockReturnValue({
      data: { user: { name: "Alice Bob", email: "alice@example.com" } },
    });
    const user = userEvent.setup();

    render(<UserButton />);
    const button = screen.getByRole("button", { name: "userMenu" });
    expect(button).toHaveAttribute("aria-haspopup", "menu");
    expect(button).toHaveAttribute("aria-expanded", "false");

    await user.click(button);
    expect(button).toHaveAttribute("aria-expanded", "true");
  });
});

"use client";

import { LogOut } from "lucide-react";
import { useTranslations } from "next-intl";
import { useEffect, useRef, useState } from "react";

import { authClient } from "@/lib/auth/client";
import { Link, useRouter } from "@/lib/i18n/navigation";

export function UserButton() {
  const t = useTranslations("auth.userMenu");
  const tNav = useTranslations("nav");
  const router = useRouter();
  // useSession is reactive — it re-renders when sign-in/sign-out happens
  // via the same authClient, so the avatar appears without a page refresh.
  const { data } = authClient.useSession();
  const session = data ? { user: data.user } : null;
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    function onClickOutside(e: MouseEvent) {
      if (ref.current && !ref.current.contains(e.target as Node)) {
        setOpen(false);
      }
    }
    document.addEventListener("mousedown", onClickOutside);
    return () => document.removeEventListener("mousedown", onClickOutside);
  }, []);

  if (!session) {
    return (
      <Link
        href="/sign-in"
        className="bg-secondary border-border text-foreground hover:bg-secondary/70 flex items-center gap-1.5 rounded-md border px-2.5 py-1 text-[12px] font-semibold transition-colors"
      >
        {t("signIn")}
      </Link>
    );
  }

  async function handleSignOut() {
    try {
      await authClient.signOut();
      router.push("/");
      router.refresh();
    } catch (err) {
      console.error("Sign-out failed:", err);
    } finally {
      setOpen(false);
    }
  }

  const initials = session.user.name
    ? session.user.name
        .split(" ")
        .map((w) => w[0])
        .join("")
        .slice(0, 2)
        .toUpperCase()
    : session.user.email[0].toUpperCase();

  return (
    <div ref={ref} className="relative">
      <button
        type="button"
        onClick={() => setOpen((p) => !p)}
        aria-haspopup="menu"
        aria-expanded={open}
        aria-label={tNav("userMenu")}
        className="bg-primary/10 border-primary/40 flex size-8 cursor-pointer items-center justify-center rounded-full border-[1.5px] text-[11px] font-bold transition hover:bg-primary/20"
      >
        <span aria-hidden className="text-primary">{initials}</span>
      </button>

      {open && (
        <div className="bg-card border-border absolute right-0 top-10 z-50 min-w-[160px] rounded-lg border py-1 shadow-lg">
          <div className="border-border border-b px-3 py-2.5">
            <p className="text-foreground truncate text-[12px] font-semibold">
              {session.user.name ?? session.user.email}
            </p>
            <p className="text-muted-foreground truncate text-[11px]">
              {session.user.email}
            </p>
          </div>
          <button
            type="button"
            onClick={handleSignOut}
            className="text-foreground hover:bg-secondary flex w-full items-center gap-2 px-3 py-2 text-left text-[12px] transition"
          >
            <LogOut className="size-3.5" />
            {t("signOut")}
          </button>
        </div>
      )}
    </div>
  );
}

