1	// Security-critical regression tests: `getDraft` and `discardDraft` must
2	// treat a non-owner request identically to a missing row, so the public
3	// contracts can't be used to probe for someone else's extensions.
4	//
5	// We don't aim to fully cover the actions here — the DB-touching paths
6	// are best exercised end-to-end. These tests pin the ownership collapse
7	// because it's exactly the kind of thing a refactor can silently undo.
8	
9	import { beforeEach, describe, expect, it, vi } from "vitest";
