258	describe("updateDraftExtension", () => {
259	  // Minimal valid form payload for ManifestFormSchema. Reused so each
260	  // test only specifies the field it actually cares about.
261	  const validValues: ManifestFormValues = {
262	    slug: "my-skill",
263	    name: "My Skill",
264	    nameZh: "",
265	    version: "1.0.0",
266	    category: "skills",
267	    scope: "personal",
268	    deptId: "",
269	    tagIds: [],
270	    summary: "Does things.",
271	    taglineZh: "",
272	    readmeMd: "",
273	    iconColor: "indigo",
274	    permissions: {},
275	    sourceMethod: "zip",
276	  };
277	
278	  it("returns unauthenticated when no session", async () => {
279	    getSessionMock.mockResolvedValue(null);
280	    const result = await updateDraftExtension("ext-1", validValues);
281	    expect(result).toEqual({ ok: false, error: "unauthenticated" });
282	    expect(selectMock).not.toHaveBeenCalled();
283	    expect(transactionMock).not.toHaveBeenCalled();
