300	  it("returns not_found for a missing extension", async () => {
301	    getSessionMock.mockResolvedValue({ user: { id: "user-A" } });
302	    selectMock.mockReturnValue(selectChain([]));
303	    const result = await updateDraftExtension("ext-missing", validValues);
304	    expect(result).toEqual({ ok: false, error: "not_found" });
305	    expect(transactionMock).not.toHaveBeenCalled();
306	  });
