308	  // Regression: non-owner MUST collapse to `not_found` so the contract
309	  // can't be used to probe whether an extension exists for someone else.
310	  it("returns not_found (not 'not_owner') for another user's extension", async () => {
311	    getSessionMock.mockResolvedValue({ user: { id: "user-A" } });
312	    selectMock.mockReturnValue(
313	      selectChain([
314	        {
315	          publisherUserId: "user-B",
316	          versionId: "v-1",
