358	    expect(result).toEqual({ ok: true });
359	    expect(transactionMock).toHaveBeenCalledTimes(1);
360	  });
361	
362	  // Regression: the wizard renders slug + version as `readOnly` in
363	  // resume mode, but readOnly is client-side only. The action must NOT
364	  // write slug or version from the request payload — otherwise a
365	  // direct call (devtools, scripted POST) could rename the slug and
366	  // orphan the already-uploaded R2 bundle at its old <slug>/<version>
367	  // key.
368	  it("does not write slug or version even when the payload tries to change them", async () => {
369	    getSessionMock.mockResolvedValue({ user: { id: "user-A" } });
370	    selectMock.mockReturnValue(
371	      selectChain([
372	        {
373	          publisherUserId: "user-A",
374	          versionId: "v-1",
375	          versionStatus: "pending",
376	        },
377	      ]),
378	    );
379	
380	    // Capture the patches the transaction body issues against `tx.update`.
381	    const updatePatches: Array<Record<string, unknown>> = [];
382	    transactionMock.mockImplementation(
383	      async (cb: (tx: unknown) => Promise<unknown>) => {
384	        const tx = {
385	          update: () => ({
386	            set: (patch: Record<string, unknown>) => {
387	              updatePatches.push(patch);
388	              return { where: () => Promise.resolve(undefined) };
389	            },
390	          }),
391	          delete: () => ({ where: () => Promise.resolve(undefined) }),
392	          insert: () => ({ values: () => Promise.resolve(undefined) }),
393	        };
394	        return cb(tx);
395	      },
396	    );
397	
398	    const attempted = {
399	      ...validValues,
400	      slug: "hijacked-slug",
401	      version: "9.9.9",
402	    };
403	    const result = await updateDraftExtension("ext-1", attempted);
404	    expect(result).toEqual({ ok: true });
