406	    // The wizard issues two patches: one against `extensions` (no slug,
407	    // no version) and one against `extension_versions` carrying just the
408	    // resumed source method. Neither must contain `slug` or `version`.
409	    expect(updatePatches).toHaveLength(2);
410	    for (const patch of updatePatches) {
411	      expect(patch).not.toHaveProperty("slug");
412	      expect(patch).not.toHaveProperty("version");
413	    }
414	    const extensionsPatch = updatePatches.find((p) =>
415	      Object.prototype.hasOwnProperty.call(p, "name"),
416	    );
417	    expect(extensionsPatch).toBeDefined();
418	    expect(extensionsPatch?.name).toBe("My Skill");
