468	describe("createDraftExtension write shape", () => {
469	  // The form schema dropped funcCat/subCat — they're now nullable in the
470	  // DB. createDraftExtension backfills them off `category` so filters
471	  // keep matching. These tests pin both the mapping and the shape of
472	  // the rows it writes (extensions, extensionVersions). If someone
473	  // re-introduces a notNull constraint, drops the backfill, or stops
474	  // persisting sourceMethod, the wizard breaks at insert and we'd only
475	  // catch it in manual QA.
476	  const baseValues: ManifestFormValues = {
477	    slug: "my-skill",
478	    name: "My Skill",
479	    nameZh: "",
480	    version: "1.0.0",
481	    category: "skills",
482	    scope: "personal",
483	    deptId: "",
484	    tagIds: [],
485	    summary: "Does things.",
486	    taglineZh: "",
487	    readmeMd: "",
488	    iconColor: "indigo",
489	    permissions: {},
490	    sourceMethod: "zip",
491	  };
492	
493	  // Capture every tx.insert(...).values(...) payload regardless of which
494	  // table is being written. We distinguish rows by their distinctive
495	  // fields (extensions row carries `slug`, extensionVersions row
496	  // carries `version` without `slug`).
497	  function captureInserts() {
498	    const inserts: Array<Record<string, unknown> | unknown> = [];
499	    transactionMock.mockImplementation(
500	      async (cb: (tx: unknown) => Promise<unknown>) => {
501	        const tx = {
502	          insert: () => ({
503	            values: (payload: unknown) => {
504	              inserts.push(payload);
505	              return Promise.resolve(undefined);
506	            },
507	          }),
508	        };
509	        return cb(tx);
510	      },
511	    );
512	    return inserts;
513	  }
514	
515	  function findExtensionsRow(rows: unknown[]) {
516	    return rows.find(
517	      (r) => typeof r === "object" && r !== null && "slug" in r,
